class Solution:
    def bstToGst(self, root):
        order = []
        def inorder(node):
            if not node:
                return
            inorder(node.left)
            order.append(node)
            inorder(node.right)
        inorder(root)
        suffix = 0
        for node in reversed(order):
            suffix += node.val
            node.val = suffix
        return root

